const crypto = require('crypto');
const h = (v) => crypto.createHash('sha256').update(v).digest('hex');

const body = $input.first().json.body;
const buyer = body.data?.buyer || {};
const purchase = body.data?.purchase || {};
const price = purchase.original_offer_price || {};

const email = (buyer.email || '').toLowerCase().trim();
const fn = (buyer.first_name || buyer.name?.split(' ')[0] || '').toLowerCase();
const ln = (buyer.last_name || buyer.name?.split(' ').slice(1).join(' ') || '').toLowerCase();
const phone = (buyer.checkout_phone || '').replace(/\D/g, '');
const tx = purchase.transaction || String(Date.now());

return [{
  json: {
    data: [{
      event_name: 'Purchase',
      event_time: Math.floor(Date.now()/1000),
      event_id: 'hotmart-' + tx,
      action_source: 'website',
      user_data: {
        em: email ? [h(email)] : undefined,
        fn: fn ? [h(fn)] : undefined,
        ln: ln ? [h(ln)] : undefined,
        ph: phone ? [h(phone)] : undefined,
        country: [h('us')]
      },
      custom_data: {
        currency: price.currency_value || 'USD',
        value: price.value || 0,
        content_name: body.data?.product?.name || 'Hotmart Product',
        order_id: tx
      }
    }]
  }
}];
